mapper.select:

WHERE cp.deleted = 0
AND cp.blinded = 0

    AND (cp.title LIKE CONCAT('%', #{keyword}, '%') OR cp.content LIKE CONCAT('%', #{keyword}, '%'))

ORDER BY cp.created_at DESC, cp.community_post_id DESC
LIMIT #{limit}
OFFSET #{offset}


WHERE cp.community_post_id = #{communityPostId}
AND cp.deleted = 0
AND cp.blinded = 0

mapper.insert:
INSERT INTO community_posts (
    member_id,
    title,
    content
) VALUES (
    #{memberId},
    #{title},
    #{content}
)

mapper.update:
UPDATE community_posts
SET deleted = 1,
    updated_at = NOW()
WHERE community_post_id = #{communityPostId}
AND member_id = #{memberId}
AND deleted = 0

mapper.insert:
INSERT IGNORE INTO community_post_views (
    community_post_id,
    member_id
) VALUES (
    #{communityPostId},
    #{memberId}
)

mapper.update:
UPDATE community_posts
SET views = (
    SELECT COUNT(*)
    FROM community_post_views cpv
    WHERE cpv.community_post_id = #{communityPostId}
)
WHERE community_post_id = #{communityPostId}
